// CONTRATO DE ENTRADA (POST /webhook/control-tower)
// { source: 'google-calendar|google-sheets|github|manual', records: [...] }
const { source, records } = $json.body ?? $json;
if (!source || !Array.isArray(records)) {
  throw new Error('Contrato inválido: se espera source y records[]');
}
const normalize = (record) => ({
  source,
  externalId: String(record.id ?? record.externalId ?? crypto.randomUUID()),
  kind: record.kind ?? (source === 'google-calendar' ? 'event' : 'project'),
  title: record.title ?? record.name ?? '(sin título)',
  owner: record.owner ?? record.assignee ?? 'Sin asignar',
  status: record.status ?? 'sin_estado',
  priority: record.priority ?? 'media',
  date: record.date ?? record.start ?? record.due ?? null,
  blocker: record.blocker ?? '',
  url: record.url ?? '',
  capturedAt: new Date().toISOString()
});
return records.map((record) => ({ json: normalize(record) }));

const items = $input.all().map((item) => item.json);
const priorityWeight = { critica: 4, alta: 3, media: 2, baja: 1 };
const needsAttention = items
  .filter((row) => ['bloqueado', 'en_riesgo', 'at_risk', 'blocked'].includes(String(row.status).toLowerCase()) || row.blocker)
  .sort((a, b) => (priorityWeight[b.priority] ?? 0) - (priorityWeight[a.priority] ?? 0));
return [{ json: {
  generatedAt: new Date().toISOString(),
  received: items.length,
  dashboard: {
    bySource: Object.groupBy(items, ({ source }) => source),
    needsAttention,
    nextSevenDays: items.filter((row) => row.date).sort((a, b) => String(a.date).localeCompare(String(b.date))).slice(0, 7)
  }
} }];
